class Solution:
    def findMaxFish(self, grid):
        rows = len(grid)
        cols = len(grid[0]) if rows else 0
        parent = list(range(rows * cols))

        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x

        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb

        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 0:
                    continue
                idx = r * cols + c
                if c + 1 < cols and grid[r][c + 1] > 0:
                    union(idx, idx + 1)
                if r + 1 < rows and grid[r + 1][c] > 0:
                    union(idx, idx + cols)

        totals = {}
        best = 0
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] == 0:
                    continue
                idx = r * cols + c
                root = find(idx)
                totals[root] = totals.get(root, 0) + grid[r][c]
                if totals[root] > best:
                    best = totals[root]
        return best

