class Solution:
    def findMaxFish(self, grid):
        rows = len(grid)
        cols = len(grid[0]) if rows else 0
        visited = [[False] * cols for _ in range(rows)]
        best = 0
        for r in range(rows):
            for c in range(cols):
                if grid[r][c] > 0 and not visited[r][c]:
                    stack = [(r, c)]
                    visited[r][c] = True
                    total = 0
                    while stack:
                        cr, cc = stack.pop()
                        total += grid[cr][cc]
                        for dr, dc in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                            nr, nc = cr + dr, cc + dc
                            if 0 <= nr < rows and 0 <= nc < cols and not visited[nr][nc] and grid[nr][nc] > 0:
                                visited[nr][nc] = True
                                stack.append((nr, nc))
                    best = max(best, total)
        return best

